package com.wjx871.population.floating;
import com.wjx871.population.common.BusinessException;import com.wjx871.population.material.*;import java.util.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Component;
@Component class FloatingRegistrationMaterialRequirementService {private final ApplicationMaterialMapper mapper;FloatingRegistrationMaterialRequirementService(ApplicationMaterialMapper m){mapper=m;}void validate(FloatingApplication a){validate(a,false);}void validateVerified(FloatingApplication a){validate(a,true);}private void validate(FloatingApplication a,boolean verified){Set<String> r=new HashSet<>(Set.of("APPLICANT_IDENTITY_PROOF","RESIDENCE_ADDRESS_PROOF"));r.add(switch(a.getResidenceReasonCode()){case "EMPLOYMENT"->"EMPLOYMENT_PROOF";case "STUDY"->"STUDY_PROOF";case "BUSINESS"->"BUSINESS_PROOF";case "FAMILY"->"FAMILY_RELATIONSHIP_PROOF";default->"OTHER_SUPPORTING_DOCUMENT";});require(a.getApplicationId(),r,verified);}private void require(Long id,Set<String> required,boolean verified){Set<String> ok=new HashSet<>();for(ApplicationMaterial m:mapper.selectByApplicationId(id))if(Boolean.TRUE.equals(m.getRequiredFlag())&&(!verified||m.getVerifyStatus()==MaterialVerifyStatus.VERIFIED))ok.add(m.getMaterialType());if(!ok.containsAll(required))throw new BusinessException(HttpStatus.CONFLICT,(verified?"缺少已核验的必需材料：":"缺少必需材料：")+String.join(",",required.stream().filter(x->!ok.contains(x)).toList()));}}
@Component class ResidencePermitMaterialRequirementService {private final ApplicationMaterialMapper mapper;ResidencePermitMaterialRequirementService(ApplicationMaterialMapper m){mapper=m;}void validate(PermitApplication a,FloatingPopulation f){validate(a,f,false);}void validateVerified(PermitApplication a,FloatingPopulation f){validate(a,f,true);}private void validate(PermitApplication a,FloatingPopulation f,boolean verified){Set<String> r=new HashSet<>();switch(a.getApplyType()){case "FIRST_ISSUE"->{r.addAll(Set.of("APPLICANT_IDENTITY_PROOF","PERSON_PHOTO","RESIDENCE_ADDRESS_PROOF"));r.add(switch(f.getResidenceReasonCode()){case "EMPLOYMENT"->"EMPLOYMENT_PROOF";case "STUDY"->"STUDY_PROOF";case "BUSINESS"->"BUSINESS_PROOF";case "FAMILY"->"FAMILY_RELATIONSHIP_PROOF";default->"OTHER_SUPPORTING_DOCUMENT";});}case "ENDORSEMENT"->r.addAll(Set.of("CURRENT_RESIDENCE_PERMIT","CONTINUED_RESIDENCE_PROOF"));case "CANCELLATION"->r.addAll(Set.of("CURRENT_RESIDENCE_PERMIT","CANCELLATION_APPLICATION"));default->throw new BusinessException(HttpStatus.BAD_REQUEST,"不支持的居住证申请类型");}Set<String> ok=new HashSet<>();for(ApplicationMaterial m:mapper.selectByApplicationId(a.getApplicationId()))if(Boolean.TRUE.equals(m.getRequiredFlag())&&(!verified||m.getVerifyStatus()==MaterialVerifyStatus.VERIFIED))ok.add(m.getMaterialType());if(!ok.containsAll(r))throw new BusinessException(HttpStatus.CONFLICT,(verified?"缺少已核验的必需材料：":"缺少必需材料：")+String.join(",",r.stream().filter(x->!ok.contains(x)).toList()));}}
